import json, subprocess, hashlib, sys

REPO = '/Users/bhyslop/projects/rbm_beta_recipemuster'
GALLOPS = '.claude/jjm/jjg_gallops.json'

ORIGIN = '1e4b438da'   # origin tip (parallel chats)
LOCAL  = '747abbca6'   # pre-rebase local HEAD (this station)
MAIN   = 'HEAD'        # rebased result

def load(ref):
    out = subprocess.check_output(['git','show',f'{ref}:{GALLOPS}'], cwd=REPO)
    return json.loads(out)

def thash(t):
    txt = t.get('jjgtn_text','')
    return hashlib.md5(txt.encode()).hexdigest()[:8]

def tack_id(t):
    return (t.get('jjgtn_ts'), t.get('jjgtn_state'), t.get('jjgtn_silks'), thash(t))

def walk(obj, heat=None, paces=None, heats=None):
    """Recursively collect: paces[coronet] = (heat, [tack_id,...]); heats set."""
    if paces is None: paces, heats = {}, set()
    if isinstance(obj, dict):
        for k, v in obj.items():
            h = heat
            if isinstance(k, str) and k.startswith('₣'):
                heats.add(k); h = k
            if isinstance(k, str) and k.startswith('₢') and isinstance(v, dict) and 'jjgpn_tacks' in v:
                paces[k] = (h, [tack_id(t) for t in v['jjgpn_tacks']])
            walk(v, h, paces, heats)
    elif isinstance(obj, list):
        for it in obj:
            walk(it, heat, paces, heats)
    return paces, heats

def summarize(name, ref):
    paces, heats = walk(load(ref))
    ntacks = sum(len(v[1]) for v in paces.values())
    print(f"  {name:8s} {ref:12s}  heats={len(heats):3d}  paces={len(paces):4d}  tacks={ntacks:5d}")
    return paces, heats

print("=== Per-version totals ===")
op, oh = summarize("origin", ORIGIN)
lp, lh = summarize("local",  LOCAL)
mp, mh = summarize("main",   MAIN)

print("\n=== Heat membership ===")
print(f"  heats in origin not in main : {sorted(oh - mh) or 'none'}")
print(f"  heats in local  not in main : {sorted(lh - mh) or 'none'}")
print(f"  heats in main not in either : {sorted(mh - (oh|lh)) or 'none'}")

print("\n=== Pace presence ===")
lost_origin = sorted(set(op) - set(mp))
lost_local  = sorted(set(lp) - set(mp))
spurious    = sorted(set(mp) - (set(op)|set(lp)))
print(f"  paces in origin missing from main : {lost_origin or 'none'}")
print(f"  paces in local  missing from main : {lost_local or 'none'}")
print(f"  paces in main absent from both    : {spurious or 'none'}")

print("\n=== Tack-level superset check (per pace) ===")
loss = []
for cor in sorted(set(op)|set(lp)):
    want = set()
    if cor in op: want |= set(op[cor][1])
    if cor in lp: want |= set(lp[cor][1])
    have = set(mp[cor][1]) if cor in mp else set()
    missing = want - have
    if missing:
        for m in sorted(missing):
            src = []
            if cor in op and m in op[cor][1]: src.append('origin')
            if cor in lp and m in lp[cor][1]: src.append('local')
            loss.append((cor, m, '+'.join(src)))
if loss:
    print("  !! LOST TACKS:")
    for cor, m, src in loss:
        print(f"     {cor}  {m}  (from {src})")
else:
    print("  OK — every tack in origin or local survives in main")

print("\n=== Spurious tacks in main (in neither parent) ===")
fab = []
for cor in sorted(mp):
    parent = set()
    if cor in op: parent |= set(op[cor][1])
    if cor in lp: parent |= set(lp[cor][1])
    for m in mp[cor][1]:
        if m not in parent:
            fab.append((cor, m))
if fab:
    print("  !! tacks present in main but in NEITHER parent:")
    for cor, m in fab:
        print(f"     {cor}  {m}")
else:
    print("  OK — main introduces no tack absent from both parents")

print("\n=== ₣BP focus: head-tack state per pace, three-way ===")
def head(paces, cor):
    if cor not in paces or not paces[cor][1]: return ('-','-')
    ts, state, silks, _ = paces[cor][1][0]
    return (state, silks)
bp = sorted({c for c in (set(op)|set(lp)|set(mp)) if mp.get(c, op.get(c, lp.get(c)))[0] == '₣BP'})
print(f"  {'coronet':9s} {'origin':28s} {'local':28s} {'main':28s}")
for c in bp:
    os_, ol_ = head(op, c)
    ls_, ll_ = head(lp, c)
    ms_, ml_ = head(mp, c)
    print(f"  {c:9s} {os_+'/'+ol_:28s} {ls_+'/'+ll_:28s} {ms_+'/'+ml_:28s}")

